import datetime
import calendar
import random

class AccountingReportGenerator:
    def __init__(self, company_name, accounting_system="Simulated"):
        self.company_name = company_name
        self.accounting_system = accounting_system
        self.data = {}  # Simulate data from accounting system

    def _generate_simulated_data(self, start_date, end_date):
        """Generates simulated accounting data for the given period."""
        self.data = {}
        current_date = start_date
        while current_date <= end_date:
            date_str = current_date.strftime("%Y-%m-%d")
            self.data[date_str] = {
                "revenue": round(random.uniform(1000, 5000), 2),
                "cost_of_goods_sold": round(random.uniform(500, 2000), 2),
                "operating_expenses": round(random.uniform(300, 1500), 2),
                "tax_rate": round(random.uniform(0.2, 0.3), 2)
            }
            current_date += datetime.timedelta(days=1)

    def generate_income_statement(self, start_date, end_date, period_type="Custom", data_source="Simulated"):
        """Generates an income statement for the specified period."""

        if data_source == "Simulated":
            self._generate_simulated_data(start_date, end_date)
        elif data_source not in ["QuickBooks", "Sage"]:
            raise ValueError("Invalid data source. Choose 'Simulated', 'QuickBooks', or 'Sage'.")

        total_revenue = 0
        total_cost_of_goods_sold = 0
        total_operating_expenses = 0

        for date_str, values in self.data.items():
            date_obj = datetime.datetime.strptime(date_str, "%Y-%m-%d").date()
            if start_date <= date_obj <= end_date:
                total_revenue += values["revenue"]
                total_cost_of_goods_sold += values["cost_of_goods_sold"]
                total_operating_expenses += values["operating_expenses"]

        gross_profit = total_revenue - total_cost_of_goods_sold
        operating_income = gross_profit - total_operating_expenses
        taxable_income = operating_income
        tax_expense = taxable_income * self.data[list(self.data.keys())[0]]["tax_rate"] if self.data else 0 # Use first day's tax rate
        net_income = operating_income - tax_expense

        report = f"""
        {self.company_name}
        Income Statement
        Period: {period_type} ({start_date.strftime("%Y-%m-%d")} - {end_date.strftime("%Y-%m-%d")})
        Data Source: {self.accounting_system}

        Revenue: ${total_revenue:.2f}
        Cost of Goods Sold: ${total_cost_of_goods_sold:.2f}
        Gross Profit: ${gross_profit:.2f}
        Operating Expenses: ${total_operating_expenses:.2f}
        Operating Income: ${operating_income:.2f}
        Tax Expense: ${tax_expense:.2f}
        Net Income: ${net_income:.2f}
        """

        return report

    def generate_monthly_report(self, year, month, data_source="Simulated"):
        """Generates a monthly income statement."""
        start_date = datetime.date(year, month, 1)
        last_day = calendar.monthrange(year, month)[1]
        end_date = datetime.date(year, month, last_day)
        return self.generate_income_statement(start_date, end_date, period_type="Monthly", data_source=data_source)

    def generate_quarterly_report(self, year, quarter, data_source="Simulated"):
        """Generates a quarterly income statement."""
        if quarter not in [1, 2, 3, 4]:
            raise ValueError("Quarter must be between 1 and 4.")

        start_month = (quarter - 1) * 3 + 1
        end_month = start_month + 2

        start_date = datetime.date(year, start_month, 1)
        last_day = calendar.monthrange(year, end_month)[1]
        end_date = datetime.date(year, end_month, last_day)

        return self.generate_income_statement(start_date, end_date, period_type="Quarterly", data_source=data_source)

    def generate_yearly_report(self, year, data_source="Simulated"):
        """Generates a yearly income statement."""
        start_date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        return self.generate_income_statement(start_date, end_date, period_type="Yearly", data_source=data_source)

