            print("Error: Invalid report type. Choose 'monthly', 'quarterly', or 'yearly'.")
            return None

        return self._format_report(report_data, start_date, end_date, purpose)

    def _generate_monthly_report(self, start_date, end_date):
        """Generates a monthly account report."""
        report_data = {}
        current_date = start_date
